import { describe, expect, it } from '@a0n/gnosis/test';
import {
  gnosisAmbientRuntimeWorkOrder,
  planGnosisStableExecutionPermutation,
  planGnosisAmbientRuntimeSchedule,
} from './ambient-scheduler';

describe('planGnosisAmbientRuntimeSchedule', () => {
  it('keeps runtime parallelism inside the memory budget', () => {
    const schedule = planGnosisAmbientRuntimeSchedule({
      foldedBytes: new Uint8Array(32).fill(11),
      cfRay: '868875887cf72f3a-SJC',
      colo: 'SJC',
      clientTcpRtt: 17,
      runtimeId: 'worker://split-a',
      timestampMs: 1_765_000_000_000,
      workItems: 96,
      memoryBudgetBytes: 4096,
      bytesPerItem: 256,
      maxParallelism: 64,
    });

    expect(schedule.kind).toBe('gnosis-ambient-runtime-schedule');
    expect(schedule.parallelism).toBeGreaterThanOrEqual(1);
    expect(schedule.parallelism).toBeLessThanOrEqual(16);
    expect(schedule.maxItemsPerChunk * schedule.parallelism * 256).toBeLessThanOrEqual(
      4096
    );
    expect(schedule.executionOrder.length).toBe(0);
    expect(schedule.inverseOrder.length).toBe(0);
    expect(schedule.outputIndices.length).toBe(0);
    expect(schedule.sourceFamilies).toContain('cf-ray');
    expect(schedule.sourceFamilies).toContain('network-weather');
  });

  it('creates a full work-order permutation without duplicate memory lanes', () => {
    const schedule = planGnosisAmbientRuntimeSchedule({
      foldedBytes: Uint8Array.from([1, 2, 3, 4, 5]),
      workItems: 31,
      memoryBudgetBytes: 2048,
      bytesPerItem: 128,
      maxParallelism: 8,
      includeExecutionPermutation: true,
    });
    const order = [...gnosisAmbientRuntimeWorkOrder(schedule, 31)];

    expect(new Set(order).size).toBe(31);
    expect(order.every((index) => index >= 0 && index < 31)).toBe(true);
    for (let slot = 0; slot < schedule.executionOrder.length; slot += 1) {
      expect(schedule.inverseOrder[schedule.executionOrder[slot]]).toBe(slot);
      expect(schedule.outputIndices[slot]).toBe(schedule.executionOrder[slot]);
    }
  });

  it('changes schedule when edge weather changes', () => {
    const base = {
      cfRay: '868875887cf72f3a-SJC',
      colo: 'SJC',
      workItems: 64,
      memoryBudgetBytes: 8192,
      bytesPerItem: 128,
      maxParallelism: 16,
      timestampMs: 1,
    };
    const first = planGnosisAmbientRuntimeSchedule({
      ...base,
      clientTcpRtt: 17,
    });
    const second = planGnosisAmbientRuntimeSchedule({
      ...base,
      clientTcpRtt: 29,
    });

    expect([first.startOffset, first.stride, first.parallelism]).not.toEqual([
      second.startOffset,
      second.stride,
      second.parallelism,
    ]);
  });

  it('uses EDGEWORK boost to admit bounded extra lanes', () => {
    const base = {
      foldedBytes: Uint8Array.from([9, 2, 6, 5]),
      workItems: 128,
      memoryBudgetBytes: 8192,
      bytesPerItem: 512,
      maxParallelism: 16,
      timestampMs: 42,
    };
    const unboosted = planGnosisAmbientRuntimeSchedule(base);
    const boosted = planGnosisAmbientRuntimeSchedule({
      ...base,
      edgeworkBoostUnits: 32,
    });

    expect(boosted.edgeworkBoostUnits).toBe(32);
    expect(boosted.edgeworkBoostLanes).toBeGreaterThanOrEqual(1);
    expect(boosted.parallelism).toBeGreaterThan(unboosted.parallelism);
    expect(boosted.parallelism).toBeLessThanOrEqual(16);
    expect(boosted.maxItemsPerChunk * boosted.parallelism * 512).toBeLessThanOrEqual(
      8192
    );
  });

  it('plans a stable cost and corridor execution permutation', () => {
    const plan = planGnosisStableExecutionPermutation({
      workItems: 5,
      costs: Uint32Array.from([3, 1, 1, 2, 1]),
      corridors: Uint32Array.from([0, 2, 1, 0, 1]),
    });

    expect([...plan.order]).toEqual([2, 4, 1, 3, 0]);
    expect([...plan.outputIndices]).toEqual([...plan.order]);
    for (let slot = 0; slot < plan.order.length; slot += 1) {
      expect(plan.inverse[plan.order[slot]]).toBe(slot);
    }
  });
});
